import { Vex } from '@vex/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

export async function handleOpenAIWebhook(event: any) {
  if (event.type === 'run.completed') {
    const threadId = event.data.thread_id;
    const runId = event.data.id;

    // Fetch assistant output
    const messages = await openai.beta.threads.messages.list(threadId);
    const codeArtifacts = extractCodeArtifacts(messages.data);

    // Vex verification
    const result = await vex.verify({
      type: 'codebase',
      code: codeArtifacts.code,
      tests: codeArtifacts.tests,
      requirements: {
        security: 'high',
        correctness: 'strict',
        secrets: 'none',
        licenses: ['MIT', 'Apache 2.0']
      }
    });

    if (!result.passed) {
      await openai.beta.threads.runs.cancel(threadId, runId);
      return { verdict: 'blocked', issues: result.issues };
    }
  }
}
